        { referencia: "1 Reis 6:7", texto: "Nem martelo, nem machado, nem nenhum instrumento de ferro se ouviu na casa enquanto se edificava." },
        { referencia: "1 Reis 6:13", texto: "E habitarei no meio dos filhos de Israel, e não desampararei o meu povo Israel." }
